sql:
SELECT news_headline
FROM market_news
WHERE stock_id = 1 AND news_date = (SELECT MAX(news_date) FROM market_news WHERE stock_id = 1);

SELECT oq.overall_quantity
FROM overall_quantity AS oq
JOIN stock_prices AS sp ON oq.stock_id = sp.stock_id AND oq.quantity_date = sp.price_date;

SELECT overall_average 
FROM overall_average 
WHERE stock_id = 1 AND average_date = '2023-01-01';

external_knowledge:
-stock_id refers to a unique identifier for a specific stock; 
-last_updated refers to the last time the stock details were updated; 
-buy_average refers to the average value at which the stock is bought.

sql:
SELECT
  (SELECT stock_symbol FROM stocks WHERE dividend_yield = (SELECT MAX(dividend_yield) FROM stocks)) AS highest_yield_stock,
  (SELECT stock_symbol FROM stocks WHERE dividend_yield = (SELECT MIN(dividend_yield) FROM stocks)) AS lowest_yield_stock;

SELECT 
  (SELECT AVG(market_cap) FROM stocks) AS avg_market_cap,
  (SELECT AVG(close_price) FROM stock_prices) AS avg_close_price;

SELECT buy_quantity 
FROM buy_quantity 
WHERE stock_id = 0 AND quantity_date = '2023-01-02';

SELECT overall_average
FROM overall_average
WHERE stock_id = 1 AND average_date = '2023-01-01';
